import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Other/auto-tagging.md","filePath":"ur/Other/auto-tagging.md","lastUpdated":1781962217000}'),d={name:"ur/Other/auto-tagging.md"};function o(n,a,c,p,g,r){return i(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging یہاں configure ہوتی ہے:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>یہ feature images کے لیے tags خودکار طور پر بناتا ہے۔ یہ tags search، random image filtering، public gallery filtering، اور age-rating access control میں کام آتے ہیں۔</p><h2 id="auto-tagging-کیا-کر-سکتی-ہے" tabindex="-1">Auto Tagging کیا کر سکتی ہے <a class="header-anchor" href="#auto-tagging-کیا-کر-سکتی-ہے" aria-label="Permalink to &quot;Auto Tagging کیا کر سکتی ہے&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>content tags بنانا</td><td>people، scenes، objects، art style، اور ملتے جلتے visual content کے tags شامل کرتا ہے۔</td></tr><tr><td>character tags بنانا</td><td>anime images اور illustrations کے لیے مفید۔</td></tr><tr><td>orientation tags شامل کرنا</td><td><code>landscape</code>، <code>portrait</code>، یا <code>square</code> شامل کرتا ہے۔</td></tr><tr><td>image rating شامل کرنا</td><td>general، sensitive، questionable، یا explicit content کے لیے <code>G/S/Q/E</code> rating results محفوظ کرتا ہے۔</td></tr><tr><td>upload پر auto-tag</td><td>نئی uploaded images خودکار طور پر tagging flow میں داخل ہوتی ہیں۔</td></tr><tr><td>Batch tagging</td><td>تمام folders یا selected folders میں پرانی images پر tags لگاتا ہے۔</td></tr></tbody></table><h2 id="پہلے-کیا-چاہیے" tabindex="-1">پہلے کیا چاہیے <a class="header-anchor" href="#پہلے-کیا-چاہیے" aria-label="Permalink to &quot;پہلے کیا چاہیے&quot;">​</a></h2><p>کم از کم ایک accessible Hugging Face Space URL تیار کریں۔</p><p>recommended طریقہ یہ ہے کہ SmilingWolf کا <code>wd-tagger</code> Space اپنے Hugging Face account میں duplicate کریں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>public Space temporary testing کے لیے استعمال ہو سکتا ہے، مگر public Spaces بہت سے users share کرتے ہیں۔ queue لگ سکتی ہے، speed کم ہو سکتی ہے، یا Space عارضی طور پر unavailable ہو سکتا ہے۔ اپنے account میں duplicated Space long-term auto tagging کے لیے زیادہ stable رہتا ہے۔</p><h2 id="smilingwolf-space-duplicate-کریں" tabindex="-1">SmilingWolf Space Duplicate کریں <a class="header-anchor" href="#smilingwolf-space-duplicate-کریں" aria-label="Permalink to &quot;SmilingWolf Space Duplicate کریں&quot;">​</a></h2><ol><li>Hugging Face میں sign in کریں۔</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> کھولیں۔</li></ol><p><img src="'+t+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>اوپر دائیں corner میں three-dot menu پر کلک کریں۔</li><li><code>Duplicate this Space</code> منتخب کریں۔</li><li>default Space name رکھیں یا اپنا نام دیں، مثلاً <code>wd-tagger</code>۔</li><li>visibility کو <code>Public</code> رکھیں۔ Public Spaces کو ImgBed سے call کرنا آسان ہوتا ہے۔</li><li>شروع میں default free hardware رکھیں۔ queue واضح مسئلہ بنے تو بعد میں upgrade کریں۔</li><li>Space create کریں اور build مکمل ہونے کا انتظار کریں۔</li></ol><p>build مکمل ہونے کے بعد اپنی Space page کھولیں۔ URL عموماً ایسا ہوتا ہے:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>browser URL copy کریں اور ImgBed کے <code>Space URLs</code> میں paste کریں۔</p><h2 id="multiple-space-urls-بھرنا" tabindex="-1">Multiple Space URLs بھرنا <a class="header-anchor" href="#multiple-space-urls-بھرنا" aria-label="Permalink to &quot;Multiple Space URLs بھرنا&quot;">​</a></h2><p>ہر line میں ایک Space URL درج کریں۔</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space۔ temporary testing کے لیے مناسب۔</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>copied Space page URL۔</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>آپ کا اپنا duplicated Space page URL۔</td></tr></tbody></table><p>آپ multiple URLs درج کر سکتے ہیں۔ ImgBed multiple Spaces کو ساتھ استعمال کرتا ہے، جس سے speed بہتر ہو سکتی ہے۔</p><p>اگر ایک Space عارضی طور پر unavailable ہو تو باقی Spaces processing جاری رکھ سکتے ہیں۔</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>تیار کیے ہوئے Space URLs درج کریں۔ کم از کم ایک استعمال کریں۔</td></tr><tr><td>Target folder</td><td>تمام folders کے لیے خالی چھوڑیں۔ صرف specific directory process کرنی ہو تو folder منتخب کریں۔</td></tr><tr><td>Recognition model</td><td>default طور پر <code>wd-swinv2-tagger-v3</code> رکھیں۔</td></tr><tr><td>General tag threshold</td><td>default زیادہ تر images کے لیے ٹھیک ہے۔ کم value زیادہ tags دیتی ہے؛ زیادہ value کم tags دیتی ہے۔</td></tr><tr><td>Character tag threshold</td><td>default conservative ہے اور غلط character tags کم کرنے میں مدد دیتا ہے۔</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>شروع میں off رکھیں۔ جب model سے tag count خود decide کروانا ہو تو on کریں۔</td></tr><tr><td>Auto-tag on upload</td><td>نئی uploaded images کو خودکار tag چاہیے ہوں تو on کریں۔</td></tr><tr><td>Start tagging</td><td>پرانی images کے لیے manual batch-tagging شروع کرتا ہے۔</td></tr></tbody></table><h2 id="recommended-starting-values" tabindex="-1">Recommended Starting Values <a class="header-anchor" href="#recommended-starting-values" aria-label="Permalink to &quot;Recommended Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>شروع میں Off</td></tr><tr><td>Auto-tag on upload</td><td>ضرورت ہو تو Enable</td></tr></tbody></table><p>اگر tags بہت زیادہ آ رہے ہوں تو general threshold تھوڑا بڑھائیں۔</p><p>اگر tags بہت کم ہوں تو general threshold تھوڑا کم کریں۔</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li><code>Space URLs</code> بھریں۔</li><li>target folder منتخب کریں۔</li><li>start tagging پر کلک کریں۔</li><li>progress مکمل ہونے کا انتظار کریں۔</li></ol><p>target folder empty ہو تو ImgBed تمام folders process کرے گا۔</p><p>Batch tagging پرانی images کے لیے بہتر ہے۔ نئی images کے لیے auto-tag on upload enable کریں تاکہ ہر بار manual run نہ کرنا پڑے۔</p><h2 id="upload-پر-auto-tag" tabindex="-1">Upload پر Auto-Tag <a class="header-anchor" href="#upload-پر-auto-tag" aria-label="Permalink to &quot;Upload پر Auto-Tag&quot;">​</a></h2><p>auto-tag on upload enabled ہونے کے بعد نئی uploaded images configured <code>Space URLs</code> کو خود call کرتی ہیں۔</p><p>یہ long-term use کے لیے مناسب ہے۔</p><p>اگر Space queue میں ہو تو upload خود پہلے finish ہو سکتا ہے، اور tagging بعد میں جاری رہتی ہے۔</p><h2 id="کون-سی-images-process-ہوتی-ہیں" tabindex="-1">کون سی Images Process ہوتی ہیں <a class="header-anchor" href="#کون-سی-images-process-ہوتی-ہیں" aria-label="Permalink to &quot;کون سی Images Process ہوتی ہیں&quot;">​</a></h2><p>Auto tagging بنیادی طور پر image files process کرتی ہے۔</p><p>جن images کے tags، orientation، rating، width، اور height پہلے سے complete ہوں، انہیں skip کیا جاتا ہے تاکہ unnecessary Space calls نہ ہوں۔</p><p>ممکن ہو تو ImgBed صرف missing information بھرتا ہے۔ مثلاً اگر صرف orientation missing ہو، تو full content tag flow call کیے بغیر orientation add کرنے کی کوشش کرتا ہے۔</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="اپنا-space-کیوں-duplicate-کریں؟" tabindex="-1">اپنا Space کیوں Duplicate کریں؟ <a class="header-anchor" href="#اپنا-space-کیوں-duplicate-کریں؟" aria-label="Permalink to &quot;اپنا Space کیوں Duplicate کریں؟&quot;">​</a></h3><p>Public Spaces بہت سے users share کرتے ہیں۔ آپ کا duplicated Space بنیادی طور پر آپ کی ImgBed site استعمال کرتی ہے، اس لیے عموماً faster اور زیادہ reliable ہوتا ہے۔</p><h3 id="space-بار-بار-starting-up-کیوں-دکھتا-ہے؟" tabindex="-1">Space بار بار Starting Up کیوں دکھتا ہے؟ <a class="header-anchor" href="#space-بار-بار-starting-up-کیوں-دکھتا-ہے؟" aria-label="Permalink to &quot;Space بار بار Starting Up کیوں دکھتا ہے؟&quot;">​</a></h3><p>پہلی creation کے بعد، یا لمبے idle period کے بعد، Space کو start ہونے میں وقت لگ سکتا ہے۔</p><p>پہلے اپنی Space page کھولیں۔ جب وہ image normally recognize کرنے لگے، ImgBed پر واپس آ کر tagging شروع کریں۔</p><h3 id="space-url-کیسے-copy-کروں؟" tabindex="-1">Space URL کیسے Copy کروں؟ <a class="header-anchor" href="#space-url-کیسے-copy-کروں؟" aria-label="Permalink to &quot;Space URL کیسے Copy کروں؟&quot;">​</a></h3><p>اپنی Hugging Face Space page کھولیں اور browser address copy کریں۔</p><p>Examples:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="کیا-multiple-spaces-شامل-کر-سکتا-ہوں؟" tabindex="-1">کیا Multiple Spaces شامل کر سکتا ہوں؟ <a class="header-anchor" href="#کیا-multiple-spaces-شامل-کر-سکتا-ہوں؟" aria-label="Permalink to &quot;کیا Multiple Spaces شامل کر سکتا ہوں؟&quot;">​</a></h3><p>ہاں۔ ہر line میں ایک Space URL درج کریں۔</p><p>Multiple Spaces images کو ساتھ process کرتے ہیں اور بہت سی images کے لیے مفید ہیں۔</p><h3 id="tags-english-میں-کیوں-ہیں؟" tabindex="-1">Tags English میں کیوں ہیں؟ <a class="header-anchor" href="#tags-english-میں-کیوں-ہیں؟" aria-label="Permalink to &quot;Tags English میں کیوں ہیں؟&quot;">​</a></h3><p>SmilingWolf models English tags output کرتے ہیں۔ یہ expected ہے۔</p><p>tags بنیادی طور پر search، filtering، random image API، اور public gallery filters کے لیے استعمال ہوتے ہیں۔</p><h3 id="rating-tags-کس-لیے-استعمال-ہوتے-ہیں؟" tabindex="-1">Rating Tags کس لیے استعمال ہوتے ہیں؟ <a class="header-anchor" href="#rating-tags-کس-لیے-استعمال-ہوتے-ہیں؟" aria-label="Permalink to &quot;Rating Tags کس لیے استعمال ہوتے ہیں؟&quot;">​</a></h3><p>rating results Security Settings کے access mode کے ساتھ کام کرتے ہیں۔</p><p>مثلاً جب visitor access age rating کے ذریعے limited ہو، public browsing اور random image features images کو انہی rules کے مطابق filter کرتے ہیں۔</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face میں sign in کریں</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger کھولیں</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Space build مکمل ہونے کا انتظار کریں</span></span>
<span class="line"><span>-&gt; اپنا Space URL copy کریں</span></span>
<span class="line"><span>-&gt; ImgBed میں Space URLs بھریں</span></span>
<span class="line"><span>-&gt; model اور thresholds منتخب کریں</span></span>
<span class="line"><span>-&gt; Start tagging یا auto-tag on upload enable کریں</span></span></code></pre></div>`,63)])])}const b=e(d,[["render",o]]);export{m as __pageData,b as default};
